// =========================================================================
// PREPARE — validate input, compute every value the downstream nodes need.
// No external API calls; pure data transformation. PROVENANCE: ported from upstream Apps Script src/Code.gs @ fce2513 — per-item line numbers in PROVENANCE.md; key anchors marked inline below.
// =========================================================================

const input = $input.first().json;
const data = input.data || {};
const config = input.config || {};

// ---- 1. Validate required fields -----------------------------------------
const REQUIRED = ['專案名稱','專案年度','承辦處室','承辦人','承辦人Email'];
for (const f of REQUIRED) {
  if (!data[f] || String(data[f]).trim() === '') {
    throw new Error('缺少必填欄位：' + f);
  }
}
for (const c of ['ROOT_FOLDER_ID','CONTROL_SHEET_ID','CALENDAR_ID','TIMEZONE']) {
  if (!config[c]) throw new Error('Missing config: ' + c);
}

// ---- 2. Helpers ----------------------------------------------------------
function sanitize(name) {
  return String(name || '')
    .replace(/[\\/:*?"<>|#%{}~&]/g, '_')
    .replace(/\s+/g, '_')
    .substring(0, 180);
}
function formatTs(date, tz, fmt) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
  }).formatToParts(date).reduce((o, p) => (o[p.type] = p.value, o), {});
  const yyyy = parts.year, MM = parts.month, dd = parts.day;
  const HH = parts.hour === '24' ? '00' : parts.hour, mm = parts.minute, ss = parts.second;
  return fmt.replace('yyyy', yyyy).replace('MM', MM).replace('dd', dd).replace('HH', HH).replace('mm', mm).replace('ss', ss);
}
function parseDate(value) {
  if (!value) return null;
  if (value instanceof Date) return new Date(value.getTime());
  const d = new Date(String(value).trim().replace(/-/g, '/'));
  return isNaN(d.getTime()) ? null : d;
}
function offsetDate(value, days) {
  const d = parseDate(value); if (!d) return null;
  d.setDate(d.getDate() + Number(days || 0)); return d;
}
function toIsoDate(d) {
  if (!d) return null;
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

// ---- 3. Project identity ------------------------------------------------
const now = new Date();
const tz = config.TIMEZONE;
const projectCode = (data['專案年度'] || '000') + '-' + (data['承辦處室'] || '未分類') + '-' + formatTs(now, tz, 'MMddHHmmss');
const createdAt = formatTs(now, tz, 'yyyy/MM/dd HH:mm');
const folderName = sanitize(`${data['專案年度']}_${data['承辦處室']}_${data['專案名稱']}`);
const docName = sanitize(`${data['專案年度']}_${data['承辦處室']}_${data['專案名稱']}_專案紀錄`);
const taskSheetName = sanitize(`${data['專案年度']}_${data['承辦處室']}_${data['專案名稱']}_待辦追蹤表`);
const checklistSheetName = sanitize(`${data['專案年度']}_${data['承辦處室']}_${data['專案名稱']}_成果檢核表`);

const SUBFOLDERS = [ // <- Code.gs:L339-353 createProjectSubFolders.folderNames
  '00_原始公文與附件','01_計畫書與核定資料','02_工作分工與會議紀錄','03_表單與回覆資料',
  '04_經費與採購核銷','05_活動照片與照片說明','06_成果資料與成果報告','07_公告通知與對外文字',
  '08_簡報與成果展示','09_檢討與下次改進','99_系統產生文件'
];

// ---- 4. Project record Doc — heading plan (for HTTP batchUpdate) -------
function kv(k, v) { return `${k}：${v || ''}`; }
const docPlan = [ // <- Code.gs:L363-420 createProjectRecordDoc (TITLE L371, HEADING_1 L373/385/390/394/397/400/407/412/417)
  { text: '行政專案紀錄文件', style: 'TITLE' },
  { text: '一、基本資料', style: 'HEADING_1' },
  { text: kv('公文主旨', data['公文主旨']) },
  { text: kv('來文單位', data['來文單位']) },
  { text: kv('公文日期', data['公文日期']) },
  { text: kv('公文文號', data['公文文號']) },
  { text: kv('專案名稱', data['專案名稱']) },
  { text: kv('專案年度', data['專案年度']) },
  { text: kv('承辦處室', data['承辦處室']) },
  { text: kv('承辦人', data['承辦人']) },
  { text: kv('承辦人Email', data['承辦人Email']) },
  { text: kv('協辦人員', data['協辦人員']) },
  { text: '二、重要期限', style: 'HEADING_1' },
  { text: kv('活動日期', data['活動日期']) },
  { text: kv('成果繳交期限', data['成果繳交期限']) },
  { text: kv('經費核銷期限', data['經費核銷期限']) },
  { text: '三、經費資訊', style: 'HEADING_1' },
  { text: kv('是否有經費', data['是否有經費']) },
  { text: kv('核定或預估金額', data['核定或預估金額']) },
  { text: '四、公文要求摘要', style: 'HEADING_1' },
  { text: '請後續使用 NotebookLM 或 Gemini 整理後補入。' },
  { text: '五、執行紀錄', style: 'HEADING_1' },
  { text: '日期｜事項｜處理情形｜負責人' },
  { text: '六、成果資料', style: 'HEADING_1' },
  { text: '照片：' }, { text: '簽到表：' }, { text: '回饋表：' }, { text: '成果報告：' }, { text: '經費附件：' },
  { text: '七、缺漏檢查', style: 'HEADING_1' },
  { text: '尚缺資料：' }, { text: '需要補件：' }, { text: '需人工確認：' },
  { text: '八、檢討與下次建議', style: 'HEADING_1' },
  { text: '本次問題：' }, { text: '下次改善：' }, { text: '可沿用資料：' },
  { text: '九、NotebookLM 建議提問', style: 'HEADING_1' },
  { text: '請根據本專案來源資料，整理公文要求、重要期限、成果報告要求、目前缺漏資料與需要人工確認的地方。' }
];
let docFullText = '';
const docStyleSpans = [];
for (const p of docPlan) {
  const start = docFullText.length + 1;
  docFullText += p.text + '\n';
  const end = docFullText.length + 1;
  if (p.style) docStyleSpans.push({ start, end, style: p.style });
}
const docRequests = [
  { insertText: { location: { index: 1 }, text: docFullText } },
  ...docStyleSpans.map(s => ({
    updateParagraphStyle: {
      range: { startIndex: s.start, endIndex: s.end },
      paragraphStyle: { namedStyleType: s.style },
      fields: 'namedStyleType'
    }
  }))
];

// ---- 5. 待辦追蹤表 — rows + validation/format requests -----------------
const owner = data['承辦人'] || '';
const eventDate = data['活動日期'] || '';
const resultDeadline = data['成果繳交期限'] || '';
const budgetDeadline = data['經費核銷期限'] || '';
const taskHeaders = ['任務編號','階段','任務名稱','任務說明','負責人','協助單位','期限','提醒日期','狀態','需要附件','附件位置','備註'];
const taskRowsArr = [ // <- Code.gs:L471-489 buildDefaultTasks (T001 L478 .. T010 L487)
  ['T001','公文','整理公文要求','確認辦理依據、期限、成果要求與附件',owner,'','','','未開始','否','',''],
  ['T002','公文','建立 NotebookLM 筆記本','將公文與附件加入專案 Notebook，並把連結貼回總控表',owner,'','','','未開始','否','',''],
  ['T003','籌備','撰寫或修正計畫書','依公文要求完成校內計畫草案',owner,'','','','未開始','是','',''],
  ['T004','籌備','建立報名或回覆表單','確認是否需收教師、家長或學生回覆',owner,'','','','未開始','否','',''],
  ['T005','執行','收集活動照片','活動期間收集照片並補上照片說明',owner,'',eventDate,eventDate,'未開始','是','',''],
  ['T006','執行','整理簽到表或參與名冊','建立人數與參與對象統計',owner,'',eventDate,eventDate,'未開始','是','',''],
  ['T007','經費','整理經費明細與憑證','確認支出項目、憑證與核銷資料',owner,'會計',budgetDeadline,budgetDeadline,'未開始','是','',''],
  ['T008','成果','撰寫成果報告草稿','使用 NotebookLM 與 Gemini 協助整理成果報告',owner,'',resultDeadline,resultDeadline,'未開始','是','',''],
  ['T009','成果','檢查成果附件是否齊全','確認照片、簽到、回饋、經費與公文附件',owner,'',resultDeadline,resultDeadline,'未開始','是','',''],
  ['T010','結案','建立下次改進建議','整理檢討與交接注意事項',owner,'','','','未開始','否','','']
];
// All 11 rows (header + 10 tasks) for `values.append` in one call
const taskAllValues = [taskHeaders, ...taskRowsArr];
// Native node items shape: one object per row keyed by header
const taskItemsForNative = taskRowsArr.map(row => {
  const obj = {}; taskHeaders.forEach((h, i) => obj[h] = row[i]); return obj;
});
const taskBatchUpdate = {
  requests: [
    { setDataValidation: {
        range: { sheetId: 0, startRowIndex: 1, endRowIndex: 1000, startColumnIndex: 8, endColumnIndex: 9 },
        rule: { condition: { type: 'ONE_OF_LIST', values: ['未開始','進行中','待確認','完成'].map(v => ({ userEnteredValue: v })) }, showCustomUi: true, strict: true }
    }},
    { repeatCell: {
        range: { sheetId: 0, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: taskHeaders.length },
        cell: { userEnteredFormat: { textFormat: { bold: true }, backgroundColor: { red: 0.92, green: 0.95, blue: 1 } } },
        fields: 'userEnteredFormat(textFormat,backgroundColor)'
    }},
    { updateSheetProperties: {
        properties: { sheetId: 0, gridProperties: { frozenRowCount: 1 } },
        fields: 'gridProperties.frozenRowCount'
    }}
  ]
};

// ---- 6. 成果檢核表 -----------------------------------------------------
const checklistHeaders = ['項目','是否需要','目前狀態','存放位置','負責人','備註'];
const checklistRowsArr = [ // <- Code.gs:L500-521 createResultChecklistSheet.rows
  ['原始公文','是','待整理','00_原始公文與附件',owner,''],
  ['計畫書或核定資料','建議','待整理','01_計畫書與核定資料',owner,''],
  ['會議紀錄或工作分工','建議','待整理','02_工作分工與會議紀錄',owner,''],
  ['表單回覆或名冊', data['是否需要收家長或教師回覆'] || '不確定','待整理','03_表單與回覆資料',owner,''],
  ['經費明細與憑證', data['是否有經費'] || '不確定','待整理','04_經費與採購核銷',owner,'需會計或主任人工確認'],
  ['活動照片與照片說明', data['是否需要活動照片'] || '不確定','待整理','05_活動照片與照片說明',owner,''],
  ['成果報告', data['是否需要成果報告'] || '不確定','待整理','06_成果資料與成果報告',owner,''],
  ['公告通知與對外文字','建議','待整理','07_公告通知與對外文字',owner,'正式公告需人工確認'],
  ['成果簡報或展示資料','視需要','待整理','08_簡報與成果展示',owner,''],
  ['檢討與下次改進','建議','待整理','09_檢討與下次改進',owner,'']
];
const checklistAllValues = [checklistHeaders, ...checklistRowsArr];
const checklistItemsForNative = checklistRowsArr.map(row => {
  const obj = {}; checklistHeaders.forEach((h, i) => obj[h] = row[i]); return obj;
});
const checklistBatchUpdate = {
  requests: [
    { setDataValidation: {
        range: { sheetId: 0, startRowIndex: 1, endRowIndex: 1000, startColumnIndex: 2, endColumnIndex: 3 },
        rule: { condition: { type: 'ONE_OF_LIST', values: ['待整理','進行中','已完成','不需要','需人工確認'].map(v => ({ userEnteredValue: v })) }, showCustomUi: true, strict: true }
    }},
    { repeatCell: {
        range: { sheetId: 0, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: checklistHeaders.length },
        cell: { userEnteredFormat: { textFormat: { bold: true }, backgroundColor: { red: 0.92, green: 0.95, blue: 1 } } },
        fields: 'userEnteredFormat(textFormat,backgroundColor)'
    }},
    { updateSheetProperties: {
        properties: { sheetId: 0, gridProperties: { frozenRowCount: 1 } },
        fields: 'gridProperties.frozenRowCount'
    }}
  ]
};

// ---- 7. Calendar events specs ------------------------------------------
const calendarEventSpecs = []; // <- Code.gs:L539-600 createCalendarReminders (活動日 L555 / 成果期限 L564 / 成果前7天 L574 / 經費 L584 / 經費前7天 L594)
const projectLabel = `${data['專案年度']}_${data['承辦處室']}_${data['專案名稱']}`;
if (data['活動日期']) {
  const d = toIsoDate(parseDate(data['活動日期']));
  if (d) calendarEventSpecs.push({ title: `【活動日】${projectLabel}`, date: d, kind: 'event' });
}
if (data['成果繳交期限']) {
  const d = toIsoDate(parseDate(data['成果繳交期限']));
  if (d) calendarEventSpecs.push({ title: `【成果期限】${projectLabel}`, date: d, kind: 'result' });
  const r = toIsoDate(offsetDate(data['成果繳交期限'], -7));
  if (r) calendarEventSpecs.push({ title: `【成果前7天提醒】${data['專案名稱']}`, date: r, kind: 'result-remind' });
}
if (data['經費核銷期限']) {
  const d = toIsoDate(parseDate(data['經費核銷期限']));
  if (d) calendarEventSpecs.push({ title: `【經費核銷期限】${projectLabel}`, date: d, kind: 'budget' });
  const r = toIsoDate(offsetDate(data['經費核銷期限'], -7));
  if (r) calendarEventSpecs.push({ title: `【經費前7天提醒】${data['專案名稱']}`, date: r, kind: 'budget-remind' });
}

// ---- 8. Control sheet row ----------------------------------------------
/* <- Code.gs:L1151-1174 getControlSheetHeaders */ const controlHeaders = ['專案編號','專案名稱','年度','承辦處室','承辦人','承辦人Email','Drive資料夾連結','專案紀錄Docs連結','待辦追蹤表連結','成果檢核表連結','NotebookLM筆記本連結','專案狀態','備註','來文單位','公文文號','建立日期','活動日期','成果期限','經費期限','是否有經費'];
const controlRowTemplate = {
  '專案編號': projectCode,
  '專案名稱': data['專案名稱'] || '',
  '年度': data['專案年度'] || '',
  '承辦處室': data['承辦處室'] || '',
  '承辦人': data['承辦人'] || '',
  '承辦人Email': data['承辦人Email'] || '',
  'Drive資料夾連結': '', '專案紀錄Docs連結': '', '待辦追蹤表連結': '', '成果檢核表連結': '',
  'NotebookLM筆記本連結': '', '專案狀態': '籌備中',
  '備註': data['備註'] || '',
  '來文單位': data['來文單位'] || '',
  '公文文號': data['公文文號'] || '',
  '建立日期': createdAt,
  '活動日期': data['活動日期'] || '',
  '成果期限': data['成果繳交期限'] || '',
  '經費期限': data['經費核銷期限'] || '',
  '是否有經費': data['是否有經費'] || ''
};

return [{
  json: {
    config, data, projectCode, createdAt, folderName, docName,
    taskSheetName, checklistSheetName, SUBFOLDERS,
    docRequests, taskHeaders, taskItemsForNative, taskBatchUpdate,
    checklistHeaders, checklistItemsForNative, checklistBatchUpdate,
    calendarEventSpecs, controlHeaders, controlRowTemplate
  }
}];

const prep = $('Prepare').first().json;
const items = $input.all();
const found = items.find(it => it.json.mimeType === 'application/vnd.google-apps.folder' || it.json.id);
if (!found) throw new Error('找不到「03_專案資料夾」子資料夾，請先執行 core-setup workflow 建立目錄結構。');
return [{ json: { ...prep, projectsParentFolderId: found.json.id } }];

const prep = $('Resolve 03 folder id').first().json;
const pf = $input.first().json;
return [{ json: { ...prep, projectFolderId: pf.id, projectFolderUrl: pf.webViewLink || `https://drive.google.com/drive/folders/${pf.id}` } }];

const { SUBFOLDERS } = $input.first().json;
const base = $input.first().json;
return SUBFOLDERS.map(name => ({ json: { ...base, subfolderName: name } }));

const all = $input.all();
const byName = {};
for (const it of all) { byName[it.json.name] = it.json.id; }
const base = $('Carry project folder').first().json;
return [{ json: { ...base, subfolderIdByName: byName, systemFolderId: byName['99_系統產生文件'] } }];

const prep = $('Collect subfolder ids').first().json;
const doc = $input.first().json;
return [{ json: { ...prep, docId: doc.documentId || doc.id } }];

const prep = $('Carry Doc URL').first().json;
const sh = $input.first().json;
return [{ json: { ...prep, taskSheetId: sh.spreadsheetId, taskSheetUrl: sh.spreadsheetUrl || `https://docs.google.com/spreadsheets/d/${sh.spreadsheetId}/edit` } }];

// Emit headers + 10 task rows as separate items so native append node writes them all.
const prep = $input.first().json;
const out = [];
const headerRow = {}; prep.taskHeaders.forEach(h => headerRow[h] = h);
out.push({ json: { _carry: prep, ...headerRow } });
for (const r of prep.taskItemsForNative) out.push({ json: { _carry: prep, ...r } });
return out;

const prep = $('Carry task sheet id').first().json;
const sh = $input.first().json;
return [{ json: { ...prep, checklistSheetId: sh.spreadsheetId, checklistSheetUrl: sh.spreadsheetUrl || `https://docs.google.com/spreadsheets/d/${sh.spreadsheetId}/edit` } }];

const prep = $input.first().json;
const out = [];
const headerRow = {}; prep.checklistHeaders.forEach(h => headerRow[h] = h);
out.push({ json: { _carry: prep, ...headerRow } });
for (const r of prep.checklistItemsForNative) out.push({ json: { _carry: prep, ...r } });
return out;

const prep = $('Carry checklist sheet id').first().json;
const { calendarEventSpecs, projectFolderUrl, taskSheetUrl, checklistSheetUrl, data, config } = prep;
const description = [
  '專案名稱：' + (data['專案名稱'] || ''),
  '承辦處室：' + (data['承辦處室'] || ''),
  '承辦人：' + (data['承辦人'] || ''),
  '',
  '請確認以下資料：',
  '1. 公文與附件',
  '2. 待辦追蹤表',
  '3. 成果檢核表',
  '4. 經費與憑證',
  '5. 活動照片與照片說明',
  '',
  'Drive 專案資料夾：' + projectFolderUrl,
  '待辦追蹤表：' + taskSheetUrl,
  '成果檢核表：' + checklistSheetUrl,
  '',
  '提醒：正式公告、經費核銷與成果送出仍需人工確認。'
].join('\n');
if (!calendarEventSpecs.length) return [{ json: { ...prep, _noEvents: true } }];
return calendarEventSpecs.map(spec => ({
  json: {
    ...prep,
    _eventTitle: spec.title,
    _eventDate: spec.date,
    _eventDateEndExclusive: (() => { const d = new Date(spec.date); d.setDate(d.getDate()+1); return d.toISOString().slice(0,10); })(),
    _eventDescription: description,
    _calendarId: config.CALENDAR_ID
  }
}));

const items = $input.all();
const prep = $('Carry checklist sheet id').first().json;
const eventIds = items.map(it => it.json.id).filter(Boolean);
return [{ json: { ...prep, calendarEventIds: eventIds } }];

const prep = $input.first().json;
const row = { ...prep.controlRowTemplate };
row['Drive資料夾連結'] = prep.projectFolderUrl || '';
row['專案紀錄Docs連結'] = prep.docUrl || '';
row['待辦追蹤表連結'] = prep.taskSheetUrl || '';
row['成果檢核表連結'] = prep.checklistSheetUrl || '';
return [{ json: { _carry: prep, ...row } }];

